import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetIgnoreHeaderCase_DefaultFalse() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_WithIgnoreHeaderCaseTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreHeaderCase(true);
        assertTrue(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_WithIgnoreHeaderCaseFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreHeaderCase(false);
        assertFalse(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_ExcelFormat() throws Exception {
        // Use reflection to create an EXCEL format with ignoreHeaderCase=true
        CSVFormat defaultFormat = CSVFormat.DEFAULT;
        CSVFormat excelFormat = defaultFormat.withIgnoreEmptyLines(false).withAllowMissingColumnNames();

        // The provided EXCEL constant does not set ignoreHeaderCase to true by default in the code above.
        // So we manually set ignoreHeaderCase = true via reflection for this test.
        java.lang.reflect.Field field = CSVFormat.class.getDeclaredField("ignoreHeaderCase");
        field.setAccessible(true);
        field.setBoolean(excelFormat, true);

        assertTrue(excelFormat.getIgnoreHeaderCase());
    }
}
